class Solution {
    public int findTheLongestSubstring(String s) {
        int countMap[][] = new int[5][26]; // 5 for 'a', 'e', 'i', 'o', 'u' and 26 for lowercase letters
        int maxLength = 0;
        for (int i = 0; i < s.length(); i++) {
            char c = s.charAt(i);
            if (countMap[c - 'a'][0] % 2 != 0) { // check if the current character is a vowel
                countMap[c - 'a'][1]++; // increment count for consonant
            } else {
                countMap[c - 'a'][0]++; // increment count for vowel
            }
            maxLength = Math.max(maxLength, i - countMap[s.charAt(i - 1] - 'a' + 1); // update maxLength if needed
        }
        return maxLength;
    }
}
```

